import { useState } from 'react';
import { paymentApi, policyApi } from '../api/api.js';
import { CreditCard, CheckCircle2, Loader2, X } from 'lucide-react';
import '../index.css';

function PaymentModal({ plan, workerId, onClose, onSuccess }) {
  const [step, setStep] = useState(1); // 1: Init, 2: Processing, 3: Success
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const handlePay = async () => {
    setLoading(true);
    setError('');

    try {
      // 1. Create Payment Intent (Mock external call)
      const intentResponse = await paymentApi.createIntent({
        policyId: plan.id, // For a real flow, a policy might not exist yet before payment
        workerId: workerId,
        amount: plan.premiumAmount,
        currency: 'INR',
        paymentMethod: 'CARD'
      });

      // Simulated payment delay of 1.5 seconds
      setStep(2);
      setTimeout(async () => {
        try {
          // 2. Actually purchase the policy on our backend
          await policyApi.purchase({ workerId, planId: plan.id });
          setStep(3);
          setTimeout(() => {
            onSuccess();
          }, 2000);
        } catch (err) {
          setError(err.message || 'Failed to complete policy purchase.');
          setStep(1);
        } finally {
          setLoading(false);
        }
      }, 1500);

    } catch (err) {
      setError(err.message || 'Failed to initialize payment.');
      setLoading(false);
      setStep(1);
    }
  };

  return (
    <div className="modal-overlay">
      <div className="modal-content glass-card" style={{ maxWidth: '400px', width: '100%' }}>

        {step !== 3 && (
          <button className="modal-close" onClick={onClose}>
            <X size={20} />
          </button>
        )}

        {step === 1 && (
          <div className="payment-init">
            <div style={{ textAlign: 'center', marginBottom: '1.5rem' }}>
              <div style={{ background: 'var(--bg-lighter)', display: 'inline-flex', padding: '1rem', borderRadius: '50%', marginBottom: '1rem' }}>
                <CreditCard size={32} color="var(--accent-blue)" />
              </div>
              <h3>Complete Payment</h3>
              <p style={{ color: 'var(--text-muted)', fontSize: '0.9rem' }}>Secure checkout via Stripe</p>
            </div>

            <div className="payment-summary" style={{ background: 'var(--bg-lighter)', padding: '1rem', borderRadius: '12px', marginBottom: '1.5rem' }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '0.5rem' }}>
                <span>Plan</span>
                <span style={{ fontWeight: 500 }}>{plan.planName}</span>
              </div>
              <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '0.5rem' }}>
                <span>Billing</span>
                <span>{plan.billingCycle === 'WEEKLY' ? 'Weekly' : 'Monthly'}</span>
              </div>
              <div style={{ height: '1px', background: 'var(--border-color)', margin: '0.8rem 0' }}></div>
              <div style={{ display: 'flex', justifyContent: 'space-between', fontWeight: 600, fontSize: '1.1rem' }}>
                <span>Total Due</span>
                <span style={{ color: 'var(--accent-blue)' }}>₹{plan.premiumAmount}</span>
              </div>
            </div>

            {error && <div className="alert alert-error" style={{ marginBottom: '1rem' }}>{error}</div>}

            {/* Skeleton Card Input */}
            <div style={{ marginBottom: '1.5rem' }}>
              <label className="form-label">Card Details</label>
              <div className="form-input" style={{ display: 'flex', alignItems: 'center', color: 'var(--text-muted)' }}>
                <CreditCard size={18} style={{ marginRight: '0.5rem' }} />
                •••• •••• •••• 4242
              </div>
              <div style={{ display: 'flex', gap: '1rem', marginTop: '0.8rem' }}>
                <div style={{ flex: 1 }}>
                  <label className="form-label">Expiry</label>
                  <div className="form-input" style={{ color: 'var(--text-muted)' }}>MM / YY</div>
                </div>
                <div style={{ flex: 1 }}>
                  <label className="form-label">CVC</label>
                  <div className="form-input" style={{ color: 'var(--text-muted)' }}>123</div>
                </div>
              </div>
            </div>

            <button 
              className="btn btn-primary btn-full" 
              onClick={handlePay}
              disabled={loading}
              style={{ display: 'flex', justifyContent: 'center', gap: '0.5rem' }}
            >
              {loading ? <><Loader2 size={18} className="spin" /> Initializing...</> : `Pay ₹${plan.premiumAmount}`}
            </button>
          </div>
        )}

        {step === 2 && (
          <div className="payment-processing" style={{ textAlign: 'center', padding: '2rem 0' }}>
            <Loader2 size={48} className="spin" color="var(--accent-blue)" style={{ margin: '0 auto 1.5rem' }} />
            <h3>Processing Payment</h3>
            <p style={{ color: 'var(--text-muted)' }}>Please do not close this window...</p>
          </div>
        )}

        {step === 3 && (
          <div className="payment-success" style={{ textAlign: 'center', padding: '2rem 0' }}>
            <div style={{ display: 'inline-flex', background: 'rgba(16, 185, 129, 0.1)', padding: '1rem', borderRadius: '50%', marginBottom: '1.5rem' }}>
              <CheckCircle2 size={48} color="var(--accent-green)" />
            </div>
            <h3 style={{ marginBottom: '0.5rem' }}>Payment Successful!</h3>
            <p style={{ color: 'var(--text-muted)' }}>Your policy is now active.</p>
          </div>
        )}

      </div>
    </div>
  );
}

export default PaymentModal;

import { useState } from 'react';
import { NavLink, useLocation } from 'react-router-dom';
import { useAuth } from '../context/AuthContext.jsx';
import { notificationApi } from '../api/api.js';
import {
  Zap, LayoutDashboard, Shield, ClipboardList, FileText,
  Bell, Settings, LogOut, MapPin, Menu, X,
  CloudSun, BarChart3, Users, ShieldCheck
} from 'lucide-react';

function Sidebar() {
  const { worker, logout, isAdmin } = useAuth();
  const [mobileOpen, setMobileOpen] = useState(false);
  const location = useLocation();

  const mainNavItems = [
    { path: '/dashboard', icon: LayoutDashboard, label: 'Dashboard' },
    { path: '/plans', icon: Shield, label: 'Plans' },
    { path: '/policies', icon: ClipboardList, label: 'My Policies' },
    { path: '/claims', icon: FileText, label: 'Claims' },
    { path: '/weather', icon: CloudSun, label: 'Weather' },
    { path: '/analytics', icon: BarChart3, label: 'Analytics' },
    { path: '/notifications', icon: Bell, label: 'Notifications', showBadge: true },
    { path: '/settings', icon: Settings, label: 'Settings' },
  ];

  const adminNavItems = [
    { path: '/admin', icon: ShieldCheck, label: 'Admin Panel' },
  ];

  const getInitials = (name) => {
    if (!name) return '?';
    return name.split(' ').map(n => n[0]).join('').toUpperCase().slice(0, 2);
  };

  return (
    <>
      <button className="mobile-menu-toggle" onClick={() => setMobileOpen(!mobileOpen)}>
        {mobileOpen ? <X size={20} /> : <Menu size={20} />}
      </button>
      <div className={`sidebar-overlay ${mobileOpen ? 'open' : ''}`} onClick={() => setMobileOpen(false)} />

      <aside className={`sidebar ${mobileOpen ? 'open' : ''}`}>
        <div className="sidebar-logo">
          <div className="sidebar-logo-icon">
            <Zap size={20} />
          </div>
          <div className="sidebar-logo-text">
            <h2>GigShield AI</h2>
            <span>Smart Insurance</span>
          </div>
        </div>

        <nav className="sidebar-nav">
          <div className="sidebar-section-label">Navigation</div>
          {mainNavItems.map(item => (
            <NavLink
              key={item.path}
              to={item.path}
              className={({ isActive }) => `nav-item ${isActive ? 'active' : ''}`}
              onClick={() => setMobileOpen(false)}
            >
              <span className="nav-icon"><item.icon size={18} /></span>
              {item.label}
            </NavLink>
          ))}

          {isAdmin && (
            <>
              <div className="sidebar-section-label" style={{ marginTop: '8px' }}>Administration</div>
              {adminNavItems.map(item => (
                <NavLink
                  key={item.path}
                  to={item.path}
                  className={({ isActive }) => `nav-item ${isActive ? 'active' : ''}`}
                  onClick={() => setMobileOpen(false)}
                >
                  <span className="nav-icon"><item.icon size={18} /></span>
                  {item.label}
                </NavLink>
              ))}
            </>
          )}
        </nav>

        <div className="sidebar-footer">
          <div className="sidebar-user">
            <div className="sidebar-user-avatar">{getInitials(worker?.fullName)}</div>
            <div className="sidebar-user-info">
              <div className="sidebar-user-name">{worker?.fullName}</div>
              <span className={`sidebar-user-role ${isAdmin ? 'admin' : 'worker'}`}>
                {isAdmin ? '★ Admin' : 'Worker'}
              </span>
              <div className="sidebar-user-city">
                <MapPin size={10} />{worker?.city}
              </div>
            </div>
          </div>
          <button className="sidebar-logout-btn" onClick={logout}>
            <LogOut size={14} /> Sign Out
          </button>
        </div>
      </aside>
    </>
  );
}

export default Sidebar;

import { createContext, useContext, useState, useCallback } from 'react';

const AuthContext = createContext(null);

export function AuthProvider({ children }) {
  const [worker, setWorker] = useState(() => {
    const saved = localStorage.getItem('gigshield_worker');
    return saved ? JSON.parse(saved) : null;
  });

  const [tokens, setTokens] = useState(() => {
    const accessToken = localStorage.getItem('gigshield_access_token');
    const refreshToken = localStorage.getItem('gigshield_refresh_token');
    return accessToken ? { accessToken, refreshToken } : null;
  });

  const login = useCallback((authResponse) => {
    // authResponse = { accessToken, refreshToken, tokenType, expiresIn, user }
    const { accessToken, refreshToken, user } = authResponse;
    setWorker(user);
    setTokens({ accessToken, refreshToken });
    localStorage.setItem('gigshield_worker', JSON.stringify(user));
    localStorage.setItem('gigshield_access_token', accessToken);
    localStorage.setItem('gigshield_refresh_token', refreshToken);
  }, []);

  const logout = useCallback(() => {
    setWorker(null);
    setTokens(null);
    localStorage.removeItem('gigshield_worker');
    localStorage.removeItem('gigshield_access_token');
    localStorage.removeItem('gigshield_refresh_token');
  }, []);

  const updateTokens = useCallback((newAccessToken, newRefreshToken) => {
    setTokens({ accessToken: newAccessToken, refreshToken: newRefreshToken });
    localStorage.setItem('gigshield_access_token', newAccessToken);
    localStorage.setItem('gigshield_refresh_token', newRefreshToken);
  }, []);

  const isAuthenticated = !!worker && !!tokens?.accessToken;
  const isAdmin = worker?.role === 'ADMIN';

  return (
    <AuthContext.Provider value={{
      worker, tokens, login, logout, updateTokens,
      isAuthenticated, isAdmin
    }}>
      {children}
    </AuthContext.Provider>
  );
}

export function useAuth() {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
}

import { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext.jsx';
import { claimApi, payoutApi } from '../api/api.js';
import LoadingSpinner from '../components/LoadingSpinner.jsx';
import {
  BarChart3, TrendingUp, FileText, Banknote,
  AlertCircle, CloudRain, Flame, Wind, Shield
} from 'lucide-react';

function Analytics() {
  const { worker } = useAuth();
  const [claims, setClaims] = useState([]);
  const [payouts, setPayouts] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => { fetchData(); }, []);

  const fetchData = async () => {
    try {
      const [claimsRes, payoutsRes] = await Promise.all([
        claimApi.getWorkerClaims(worker.id),
        payoutApi.getWorkerPayouts(worker.id),
      ]);
      setClaims(claimsRes.data || []);
      setPayouts(payoutsRes.data || []);
    } catch (err) { setError(err.message); }
    finally { setLoading(false); }
  };

  const formatCurrency = (val) => {
    if (!val) return '₹0';
    return '₹' + Number(val).toLocaleString('en-IN', { maximumFractionDigits: 0 });
  };

  if (loading) return <LoadingSpinner />;

  // Compute analytics
  const totalClaims = claims.length;
  const approved = claims.filter(c => c.status === 'APPROVED' || c.status === 'PAID').length;
  const rejected = claims.filter(c => c.status === 'REJECTED').length;
  const pending = claims.filter(c => c.status === 'PENDING').length;

  const rainClaims = claims.filter(c => c.eventType === 'HEAVY_RAIN').length;
  const heatClaims = claims.filter(c => c.eventType === 'EXTREME_HEAT').length;
  const pollutionClaims = claims.filter(c => c.eventType === 'HIGH_POLLUTION').length;
  const maxEventCount = Math.max(rainClaims, heatClaims, pollutionClaims, 1);

  const totalPayoutAmt = payouts
    .filter(p => p.status === 'COMPLETED')
    .reduce((sum, p) => sum + Number(p.amount || 0), 0);
  const avgPayoutAmt = payouts.length > 0 ? totalPayoutAmt / payouts.filter(p => p.status === 'COMPLETED').length : 0;

  const avgRisk = claims.length > 0
    ? (claims.reduce((sum, c) => sum + Number(c.riskScore || 0), 0) / claims.length)
    : 0;

  // Risk distribution
  const lowRisk = claims.filter(c => Number(c.riskScore) < 0.4).length;
  const medRisk = claims.filter(c => Number(c.riskScore) >= 0.4 && Number(c.riskScore) < 0.7).length;
  const highRisk = claims.filter(c => Number(c.riskScore) >= 0.7).length;
  const maxRiskCount = Math.max(lowRisk, medRisk, highRisk, 1);

  return (
    <div>
      <div className="page-header">
        <h1>
          <div className="page-header-icon" style={{ background: 'var(--accent-teal-glow)', color: 'var(--accent-teal)' }}>
            <BarChart3 size={20} />
          </div>
          Analytics
        </h1>
        <p>Insights into your claims, payouts, and risk profile</p>
      </div>

      {error && <div className="alert alert-error"><AlertCircle size={16} /> {error}</div>}

      {/* Summary Metrics */}
      <div className="metrics-grid stagger-children" style={{ gridTemplateColumns: 'repeat(auto-fit, minmax(180px, 1fr))' }}>
        <div className="glass-card" style={{ textAlign: 'center' }}>
          <FileText size={20} style={{ color: 'var(--accent-teal)', marginBottom: 8 }} />
          <div style={{ fontSize: '1.5rem', fontWeight: 800, color: 'var(--accent-teal)' }}>{totalClaims}</div>
          <div style={{ fontSize: '0.78rem', color: 'var(--text-muted)', marginTop: 4 }}>Total Claims</div>
        </div>
        <div className="glass-card" style={{ textAlign: 'center' }}>
          <TrendingUp size={20} style={{ color: 'var(--accent-emerald)', marginBottom: 8 }} />
          <div style={{ fontSize: '1.5rem', fontWeight: 800, color: 'var(--accent-emerald)' }}>{formatCurrency(totalPayoutAmt)}</div>
          <div style={{ fontSize: '0.78rem', color: 'var(--text-muted)', marginTop: 4 }}>Total Earned</div>
        </div>
        <div className="glass-card" style={{ textAlign: 'center' }}>
          <Banknote size={20} style={{ color: 'var(--accent-amber)', marginBottom: 8 }} />
          <div style={{ fontSize: '1.5rem', fontWeight: 800, color: 'var(--accent-amber)' }}>{formatCurrency(avgPayoutAmt)}</div>
          <div style={{ fontSize: '0.78rem', color: 'var(--text-muted)', marginTop: 4 }}>Avg Payout</div>
        </div>
        <div className="glass-card" style={{ textAlign: 'center' }}>
          <Shield size={20} style={{ color: 'var(--accent-coral)', marginBottom: 8 }} />
          <div style={{ fontSize: '1.5rem', fontWeight: 800, color: 'var(--accent-coral)' }}>{avgRisk.toFixed(2)}</div>
          <div style={{ fontSize: '0.78rem', color: 'var(--text-muted)', marginTop: 4 }}>Avg Risk Score</div>
        </div>
      </div>

      <div className="analytics-grid">
        {/* Claims by Event Type */}
        <div className="analytics-card">
          <h3><CloudRain size={18} style={{ color: 'var(--accent-sky)' }} /> Claims by Event Type</h3>
          <div className="bar-chart">
            <div className="bar-row">
              <div className="bar-label" style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
                <CloudRain size={14} /> Heavy Rain
              </div>
              <div className="bar-track">
                <div className="bar-fill teal" style={{ width: `${(rainClaims/maxEventCount)*100}%` }}>
                  {rainClaims}
                </div>
              </div>
            </div>
            <div className="bar-row">
              <div className="bar-label" style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
                <Flame size={14} /> Extreme Heat
              </div>
              <div className="bar-track">
                <div className="bar-fill amber" style={{ width: `${(heatClaims/maxEventCount)*100}%` }}>
                  {heatClaims}
                </div>
              </div>
            </div>
            <div className="bar-row">
              <div className="bar-label" style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
                <Wind size={14} /> High Pollution
              </div>
              <div className="bar-track">
