import { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext.jsx';
import { claimApi, invoiceApi } from '../api/api.js';
import LoadingSpinner from '../components/LoadingSpinner.jsx';
import {
  FileText, CheckCircle2, XCircle, AlertCircle,
  Banknote, Clock, ShieldCheck, Download, Loader2
} from 'lucide-react';

function Claims() {
  const { worker } = useAuth();
  const [claims, setClaims] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [downloading, setDownloading] = useState(null);

  useEffect(() => { fetchClaims(); }, []);

  const fetchClaims = async () => {
    try {
      const response = await claimApi.getWorkerClaims(worker.id);
      setClaims(response.data?.content || response.data || []);
    } catch (err) { setError(err.message); }
    finally { setLoading(false); }
  };

  const handleDownloadInvoice = async (claimId) => {
    setDownloading(claimId);
    try {
      const response = await invoiceApi.downloadClaimInvoice(claimId);
      const blob = new Blob([response], { type: 'application/pdf' });
      const url = window.URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.setAttribute('download', `notice_claim_${claimId}.pdf`);
      document.body.appendChild(link);
      link.click();
      link.parentNode.removeChild(link);
    } catch (err) {
      setError('Failed to download settlement notice');
    } finally {
      setDownloading(null);
    }
  };

  const formatCurrency = (val) => {
    if (!val) return '₹0';
    return '₹' + Number(val).toLocaleString('en-IN', { maximumFractionDigits: 0 });
  };

  const formatDateTime = (dt) => {
    if (!dt) return '—';
    try {
      return new Date(dt).toLocaleString('en-IN', {
        day: '2-digit', month: 'short', year: 'numeric',
        hour: '2-digit', minute: '2-digit'
      });
    } catch { return dt; }
  };

  if (loading) return <LoadingSpinner />;

  return (
    <div>
      <div className="page-header">
        <h1>
          <div className="page-header-icon" style={{ background: 'var(--accent-amber-glow)', color: 'var(--accent-amber)' }}>
            <FileText size={20} />
          </div>
          My Claims
        </h1>
        <p>Track all your insurance claims and payouts</p>
      </div>

      {error && <div className="alert alert-error"><AlertCircle size={16} /> {error}</div>}

      {claims.length > 0 ? (
        <div className="table-container">
          <table className="data-table">
            <thead>
              <tr>
                <th>Claim #</th><th>Plan</th><th>Event</th><th>Risk Score</th>
                <th>Est. Loss</th><th>Claim Amt</th><th>Fraud Check</th>
                <th>Status</th><th>Payout</th><th>Triggered</th><th>Actions</th>
              </tr>
            </thead>
            <tbody>
              {claims.map((claim) => {
                const riskVal = Number(claim.riskScore);
                const riskClass = riskVal >= 0.7 ? 'risk-high' : riskVal >= 0.4 ? 'risk-medium' : 'risk-low';
                return (
                  <tr key={claim.id}>
                    <td style={{ fontWeight: 700 }}>#{claim.id}</td>
                    <td style={{ color: 'var(--text-primary)' }}>{claim.planName}</td>
                    <td><span className="badge badge-info">{claim.eventType}</span></td>
                    <td>
                      <span className={`risk-score ${riskClass}`}>
                        {riskVal.toFixed(2)}
                        <span className="risk-bar">
                          <span className="risk-bar-fill" style={{ width: `${riskVal * 100}%` }} />
                        </span>
                      </span>
                    </td>
                    <td>{formatCurrency(claim.estimatedLoss)}</td>
                    <td style={{ fontWeight: 600, color: 'var(--accent-blue)' }}>{formatCurrency(claim.claimAmount)}</td>
                    <td>
                      {claim.fraudCheckPassed
                        ? <span style={{ color: 'var(--accent-emerald)', display: 'flex', alignItems: 'center', gap: 4 }}><ShieldCheck size={14} /> Passed</span>
                        : <span style={{ color: 'var(--accent-rose)', display: 'flex', alignItems: 'center', gap: 4 }}><XCircle size={14} /> Failed</span>
                      }
                    </td>
                    <td><span className={`badge badge-${claim.status?.toLowerCase()}`}>{claim.status}</span></td>
                    <td>
                      {claim.payoutAmount ? (
                        <div>
                          <div style={{ fontWeight: 600, color: 'var(--accent-emerald)', display: 'flex', alignItems: 'center', gap: 4 }}>
                            <Banknote size={14} /> {formatCurrency(claim.payoutAmount)}
                          </div>
                          <div style={{ fontSize: '0.7rem', color: 'var(--text-muted)' }}>{claim.payoutStatus}</div>
                        </div>
                      ) : (
                        <span style={{ color: 'var(--text-muted)' }}>—</span>
                      )}
                    </td>
                    <td style={{ fontSize: '0.8rem' }}>{formatDateTime(claim.triggeredAt)}</td>
                    <td>
                      <button
                        className="btn btn-outline btn-sm"
                        onClick={() => handleDownloadInvoice(claim.id)}
                        disabled={downloading === claim.id}
                        title="Download Settlement Notice"
                        style={{ padding: '4px 8px' }}
                      >
                        {downloading === claim.id ? <Loader2 size={14} style={{ animation: 'spin 1s linear infinite' }} /> : <Download size={14} />}
                      </button>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      ) : (
        <div className="glass-card empty-state">
          <div className="empty-state-icon"><FileText size={28} /></div>
          <h3>No claims yet</h3>
          <p>Claims are automatically triggered when environmental events affect your area</p>
        </div>
      )}
    </div>
  );
}

export default Claims;

import { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext.jsx';
import { notificationApi } from '../api/api.js';
import LoadingSpinner from '../components/LoadingSpinner.jsx';
import {
  Bell, FileText, CloudSun, Shield, Banknote,
  CheckCheck, AlertCircle
} from 'lucide-react';

function Notifications() {
  const { worker } = useAuth();
  const [notifications, setNotifications] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [filter, setFilter] = useState('all');

  useEffect(() => { fetchNotifications(); }, []);

  const fetchNotifications = async () => {
    try {
      const response = await notificationApi.getWorkerNotifications(worker.id);
      setNotifications(response.data || []);
    } catch (err) { setError(err.message); }
    finally { setLoading(false); }
  };

  const handleMarkRead = async (id) => {
    try {
      await notificationApi.markAsRead(id);
      setNotifications(notifications.map(n => n.id === id ? { ...n, isRead: true } : n));
    } catch (err) { console.error('Failed to mark notification as read:', err); }
  };

  const formatTime = (dt) => {
    if (!dt) return '';
    try {
      const date = new Date(dt);
      const now = new Date();
      const diff = now - date;
      const mins = Math.floor(diff / 60000);
      const hours = Math.floor(diff / 3600000);
      const days = Math.floor(diff / 86400000);
      if (mins < 1) return 'Just now';
      if (mins < 60) return `${mins}m ago`;
      if (hours < 24) return `${hours}h ago`;
      if (days < 7) return `${days}d ago`;
      return date.toLocaleDateString('en-IN', { day: '2-digit', month: 'short' });
    } catch { return dt; }
  };

  const getTypeInfo = (type) => {
    switch (type) {
      case 'CLAIM_UPDATE': return { icon: <FileText size={18} />, cls: 'claim' };
      case 'WEATHER_ALERT': return { icon: <CloudSun size={18} />, cls: 'weather' };
      case 'POLICY_REMINDER': return { icon: <Shield size={18} />, cls: 'policy' };
      case 'PAYOUT_UPDATE': return { icon: <Banknote size={18} />, cls: 'payout' };
      default: return { icon: <Bell size={18} />, cls: 'default' };
    }
  };

  if (loading) return <LoadingSpinner />;

  const unreadCount = notifications.filter(n => !n.isRead).length;

  const filtered = filter === 'all' ? notifications
    : filter === 'unread' ? notifications.filter(n => !n.isRead)
    : notifications.filter(n => n.type === filter);

  return (
    <div>
      <div className="page-header">
        <h1>
          <div className="page-header-icon" style={{ background: 'var(--accent-rose-glow)', color: 'var(--accent-rose)' }}>
            <Bell size={20} />
          </div>
          Notifications
          {unreadCount > 0 && <span className="badge badge-info" style={{ fontSize: '0.75rem', marginLeft: 8 }}>{unreadCount} new</span>}
        </h1>
        <p>Stay updated on claims, payouts, and weather alerts</p>
      </div>

      {error && <div className="alert alert-error"><AlertCircle size={16} /> {error}</div>}

      <div className="filter-tabs">
        {[
          { key: 'all', label: 'All' },
          { key: 'unread', label: 'Unread' },
          { key: 'CLAIM_UPDATE', label: 'Claims' },
          { key: 'WEATHER_ALERT', label: 'Weather' },
          { key: 'PAYOUT_UPDATE', label: 'Payouts' },
        ].map(tab => (
          <button key={tab.key}
            className={`filter-tab ${filter === tab.key ? 'active' : ''}`}
            onClick={() => setFilter(tab.key)}
          >
            {tab.label}
          </button>
        ))}
      </div>

      {filtered.length > 0 ? (
        <div className="glass-card" style={{ padding: 0, overflow: 'hidden' }}>
          {filtered.map((notification, idx) => {
            const typeInfo = getTypeInfo(notification.type);
            return (
              <div
                key={notification.id}
                className={`notification-item ${!notification.isRead ? 'unread' : ''}`}
                onClick={() => !notification.isRead && handleMarkRead(notification.id)}
                style={{ animationDelay: `${idx * 40}ms` }}
              >
                <div className={`notification-icon-wrapper ${typeInfo.cls}`}>
                  {typeInfo.icon}
                </div>
                <div className="notification-content">
                  <div className="notification-title">{notification.title}</div>
                  <div className="notification-message">{notification.message}</div>
                  <div className="notification-time">{formatTime(notification.createdAt)}</div>
                </div>
                {!notification.isRead && (
                  <button
                    className="btn btn-sm btn-ghost"
                    onClick={(e) => { e.stopPropagation(); handleMarkRead(notification.id); }}
                    style={{ flexShrink: 0, alignSelf: 'center' }}
                  >
                    <CheckCheck size={15} />
                  </button>
                )}
              </div>
            );
          })}
        </div>
      ) : (
        <div className="glass-card empty-state">
          <div className="empty-state-icon"><Bell size={28} /></div>
          <h3>{filter !== 'all' ? 'No matching notifications' : 'No notifications'}</h3>
          <p>{filter !== 'all' ? 'Try a different filter' : "You're all caught up! Notifications will appear here when there are updates."}</p>
        </div>
      )}
    </div>
  );
}

export default Notifications;

import { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext.jsx';
import { policyApi } from '../api/api.js';
import LoadingSpinner from '../components/LoadingSpinner.jsx';
import {
  Shield, CloudRain, Flame, Wind, CheckCircle2,
  Star, AlertCircle, Loader2
} from 'lucide-react';
import PaymentModal from '../components/PaymentModal.jsx';

function Plans() {
  const { worker } = useAuth();
  const [plans, setPlans] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [selectedPlanForPayment, setSelectedPlanForPayment] = useState(null);
  const [successMsg, setSuccessMsg] = useState('');

  // Advanced View States
  const [viewMode, setViewMode] = useState('grid');
  const [filterCoverage, setFilterCoverage] = useState('ANY');
  const [sortBy, setSortBy] = useState('popular');
  const [expandedPlanId, setExpandedPlanId] = useState(null);

  useEffect(() => { fetchPlans(); }, []);

  const fetchPlans = async () => {
    try {
      const response = await policyApi.getPlans();
      setPlans(response.data || []);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  const handlePurchaseClick = (plan) => {
    setSelectedPlanForPayment(plan);
    setSuccessMsg('');
    setError('');
  };

  const handlePaymentSuccess = () => {
    setSelectedPlanForPayment(null);
    setSuccessMsg('Policy purchased successfully! Check your policies page.');
    setTimeout(() => setSuccessMsg(''), 5000);
  };

  const getCoverageIcon = (type) => {
    switch (type) {
      case 'RAIN': return <CloudRain size={22} />;
      case 'HEAT': return <Flame size={22} />;
      case 'POLLUTION': return <Wind size={22} />;
      case 'ALL': return <Shield size={22} />;
      default: return <Shield size={22} />;
    }
  };

  const getCoverageClass = (type) => {
    switch (type) {
      case 'RAIN': return 'rain';
      case 'HEAT': return 'heat';
      case 'POLLUTION': return 'pollution';
      case 'ALL': return 'all';
      default: return '';
    }
  };

  const formatCurrency = (val) => {
    if (!val) return '₹0';
    return '₹' + Number(val).toLocaleString('en-IN', { maximumFractionDigits: 0 });
  };

  const getFeatures = (plan) => {
    const features = [
      `${plan.coverageType === 'ALL' ? 'All weather' : plan.coverageType.charAt(0) + plan.coverageType.slice(1).toLowerCase()} event coverage`,
      `Up to ${formatCurrency(plan.maxPayout)} payout`,
      `${plan.billingCycle === 'WEEKLY' ? 'Weekly' : 'Monthly'} billing cycle`,
      'AI-powered risk assessment',
      'Automatic claim triggering',
    ];
    if (plan.coverageType === 'ALL') features.push('Combined protection');
    return features;
  };

  const processedPlans = [...plans]
    .filter(p => filterCoverage === 'ANY' || p.coverageType === filterCoverage)
    .sort((a, b) => {
      if (sortBy === 'price_asc') return a.premiumAmount - b.premiumAmount;
      if (sortBy === 'price_desc') return b.premiumAmount - a.premiumAmount;
      if (sortBy === 'payout_desc') return b.maxPayout - a.maxPayout;
      // Default: popular first
      const aPop = a.coverageType === 'ALL' && a.billingCycle === 'MONTHLY' ? 1 : 0;
      const bPop = b.coverageType === 'ALL' && b.billingCycle === 'MONTHLY' ? 1 : 0;
      return bPop - aPop;
    });

  if (loading) return <LoadingSpinner />;

  return (
    <div className="animate-fade-in">
      <div className="page-header" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-end', flexWrap: 'wrap', gap: 'var(--space-md)' }}>
        <div>
          <h1 className="animate-fade-in-up">
            <div className="page-header-icon" style={{ background: 'var(--accent-blue-glow)', color: 'var(--info)' }}>
              <Shield size={20} />
            </div>
            Insurance Plans
          </h1>
          <p className="animate-fade-in-up" style={{ animationDelay: '100ms' }}>Choose the right protection for your gig income</p>
        </div>

        {/* Controls */}
        <div className="plans-controls animate-fade-in-up" style={{ display: 'flex', gap: '12px', flexWrap: 'wrap', animationDelay: '200ms' }}>
          <select 
            className="form-input" 
            style={{ width: 'auto', padding: '8px 12px', height: 'auto', fontSize: '0.85rem' }}
            value={filterCoverage}
            onChange={(e) => setFilterCoverage(e.target.value)}
          >
            <option value="ANY">All Coverage</option>
            <option value="ALL">Comprehensive</option>
            <option value="RAIN">Rain Only</option>
            <option value="HEAT">Heat Only</option>
          </select>

          <select 
            className="form-input" 
            style={{ width: 'auto', padding: '8px 12px', height: 'auto', fontSize: '0.85rem' }}
            value={sortBy}
            onChange={(e) => setSortBy(e.target.value)}
          >
            <option value="popular">Recommended</option>
            <option value="price_asc">Price: Low to High</option>
            <option value="price_desc">Price: High to Low</option>
            <option value="payout_desc">Max Payout</option>
          </select>

          <div className="filter-tabs" style={{ margin: 0 }}>
            <button className={`filter-tab ${viewMode === 'grid' ? 'active' : ''}`} onClick={() => setViewMode('grid')} style={{ background: viewMode === 'grid' ? 'var(--bg-card)' : 'transparent', color: viewMode === 'grid' ? 'var(--text-primary)' : 'var(--text-secondary)' }}>Grid</button>
            <button className={`filter-tab ${viewMode === 'table' ? 'active' : ''}`} onClick={() => setViewMode('table')} style={{ background: viewMode === 'table' ? 'var(--bg-card)' : 'transparent', color: viewMode === 'table' ? 'var(--text-primary)' : 'var(--text-secondary)' }}>Table</button>
          </div>
        </div>
      </div>

      {error && <div className="alert alert-error animate-fade-in"><AlertCircle size={16} /> {error}</div>}
      {successMsg && <div className="alert alert-success animate-fade-in"><CheckCircle2 size={16} /> {successMsg}</div>}

      {viewMode === 'grid' ? (
        <div className="cards-grid stagger-children">
          {processedPlans.map((plan, idx) => {
          const isPopular = plan.coverageType === 'ALL' && plan.billingCycle === 'MONTHLY';
          return (
            <div key={plan.id} className={`plan-card ${getCoverageClass(plan.coverageType)} ${isPopular ? 'popular' : ''}`}>
              <div className="plan-card-header">
                {isPopular && <div className="plan-popular-badge"><Star size={10} /> Most Popular</div>}
                <div className={`plan-icon ${getCoverageClass(plan.coverageType)}`}>
                  {getCoverageIcon(plan.coverageType)}
                </div>
                <div className="plan-name">{plan.planName}</div>
                <div className="plan-description">{plan.description}</div>
              </div>

              <div className="plan-card-body">
                <div className="plan-price">
                  <span className="plan-price-amount">{formatCurrency(plan.premiumAmount)}</span>
                  <span className="plan-price-period">/{plan.billingCycle === 'WEEKLY' ? 'week' : 'month'}</span>
                </div>

                <ul className="plan-features">
                  {getFeatures(plan).map((feature, i) => (
                    <li key={i} className="plan-feature">
                      <CheckCircle2 size={14} className="plan-feature-icon" />
                      {feature}
                    </li>
                  ))}
                </ul>

                <button
                  className={`btn ${isPopular ? 'btn-primary' : 'btn-outline'} btn-full`}
                  onClick={() => handlePurchaseClick(plan)}
                  style={{ marginTop: 'auto' }}
                >
                  Get This Plan
                </button>
                <div 
                  style={{ textAlign: 'center', marginTop: '12px', fontSize: '0.8rem', color: 'var(--primary)', cursor: 'pointer' }}
                  onClick={() => setExpandedPlanId(expandedPlanId === plan.id ? null : plan.id)}
                >
                  {expandedPlanId === plan.id ? 'Hide Details' : 'View Details'}
                </div>
                {expandedPlanId === plan.id && (
                  <div className="animate-fade-in-up" style={{ marginTop: '16px', padding: '12px', background: 'rgba(255,255,255,0.03)', borderRadius: 'var(--radius-sm)', fontSize: '0.8rem', color: 'var(--text-secondary)' }}>
                    <p style={{ margin: 0, marginBottom: '8px' }}><strong>Deductible:</strong> ₹0</p>
                    <p style={{ margin: 0, marginBottom: '8px' }}><strong>Waiting Period:</strong> None</p>
                    <p style={{ margin: 0 }}><strong>Policy Term:</strong> {plan.billingCycle === 'WEEKLY' ? '7 Days' : '30 Days'} Auto-renewing</p>
                  </div>
                )}
              </div>
            </div>
          );
        })}
      </div>
      ) : (
        <div className="table-container animate-fade-in-up" style={{ marginTop: 'var(--space-md)' }}>
          <table className="data-table">
            <thead style={{ position: 'sticky', top: 0, zIndex: 10, background: 'var(--bg-card)' }}>
              <tr>
                <th>Plan Name</th>
                <th>Coverage</th>
                <th>Premium</th>
                <th>Max Payout</th>
                <th>Billing</th>
                <th>Action</th>
              </tr>
            </thead>
            <tbody>
              {processedPlans.map(plan => {
                const isPopular = plan.coverageType === 'ALL' && plan.billingCycle === 'MONTHLY';
                return (
                  <tr key={plan.id}>
                    <td style={{ fontWeight: 600 }}>
                      <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                        {getCoverageIcon(plan.coverageType)}
                        {plan.planName}
                        {isPopular && <span className="badge badge-success" style={{ fontSize: '0.65rem' }}>Popular</span>}
                      </div>
                    </td>
                    <td><span className={`badge badge-info`}>{plan.coverageType}</span></td>
                    <td style={{ fontWeight: 600, color: 'var(--text-primary)' }}>{formatCurrency(plan.premiumAmount)}</td>
                    <td>{formatCurrency(plan.maxPayout)}</td>
                    <td>{plan.billingCycle}</td>
                    <td>
                      <button className="btn btn-sm btn-primary" onClick={() => handlePurchaseClick(plan)}>Select</button>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      )}

      {plans.length === 0 && (
        <div className="glass-card empty-state">
          <div className="empty-state-icon"><Shield size={28} /></div>
          <h3>No plans available yet</h3>
          <p>Insurance plans will appear here once configured</p>
        </div>
      )}

      {selectedPlanForPayment && (
        <PaymentModal 
          plan={selectedPlanForPayment} 
          workerId={worker.id}
          onClose={() => setSelectedPlanForPayment(null)}
          onSuccess={handlePaymentSuccess}
        />
      )}
    </div>
  );
}

export default Plans;

import { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext.jsx';
import { policyApi, invoiceApi } from '../api/api.js';
import LoadingSpinner from '../components/LoadingSpinner.jsx';
import {
  ClipboardList, Shield, CloudRain, Flame, Wind,
  Calendar, Banknote, AlertCircle, XCircle, Loader2, Download
} from 'lucide-react';

function Policies() {
  const { worker } = useAuth();
  const [policies, setPolicies] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [cancelling, setCancelling] = useState(null);
  const [downloading, setDownloading] = useState(null);

  useEffect(() => { fetchPolicies(); }, []);

  const fetchPolicies = async () => {
    try {
      const response = await policyApi.getWorkerPolicies(worker.id);
      setPolicies(response.data?.content || response.data || []);
    } catch (err) { setError(err.message); }
    finally { setLoading(false); }
  };

  const handleCancel = async (policyId) => {
    if (!window.confirm('Are you sure you want to cancel this policy? This action cannot be undone.')) return;
    setCancelling(policyId);
    try {
      await policyApi.cancel(policyId);
      fetchPolicies();
    } catch (err) { setError(err.message); }
    finally { setCancelling(null); }
  };

  const handleDownloadInvoice = async (policyId) => {
    setDownloading(policyId);
    try {
      const response = await invoiceApi.downloadPolicyInvoice(policyId);
      const blob = new Blob([response], { type: 'application/pdf' });
      const url = window.URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.setAttribute('download', `invoice_policy_${policyId}.pdf`);
      document.body.appendChild(link);
      link.click();
      link.parentNode.removeChild(link);
    } catch (err) {
      setError('Failed to download invoice');
    } finally {
      setDownloading(null);
    }
  };

  const formatCurrency = (val) => {
    if (!val) return '₹0';
    return '₹' + Number(val).toLocaleString('en-IN', { maximumFractionDigits: 0 });
  };

  const getCoverageIcon = (type) => {
    switch (type) {
      case 'RAIN': return <CloudRain size={18} />;
      case 'HEAT': return <Flame size={18} />;
      case 'POLLUTION': return <Wind size={18} />;
      default: return <Shield size={18} />;
    }
  };

  const getStatusClass = (status) => {
    switch (status) {
      case 'ACTIVE': return 'active-policy';
      case 'EXPIRED': return 'expired-policy';
      case 'CANCELLED': return 'cancelled-policy';
      default: return '';
    }
  };

  if (loading) return <LoadingSpinner />;

  return (
    <div>
      <div className="page-header">
        <h1>
          <div className="page-header-icon" style={{ background: 'var(--accent-purple-glow)', color: 'var(--accent-purple)' }}>
            <ClipboardList size={20} />
          </div>
          My Policies
        </h1>
        <p>Manage your active insurance policies</p>
      </div>

      {error && <div className="alert alert-error"><AlertCircle size={16} /> {error}</div>}

      {policies.length > 0 ? (
        <div className="cards-grid stagger-children">
          {policies.map((policy) => (
            <div key={policy.id} className={`policy-card ${getStatusClass(policy.status)}`}>
              <div className="policy-card-header">
                <div>
                  <div className="policy-card-title">{policy.planName}</div>
                  <div className="policy-card-id">Policy #{policy.id}</div>
                </div>
                <span className={`badge badge-${policy.status?.toLowerCase()}`}>{policy.status}</span>
              </div>

              <div className="policy-card-details">
                <div className="policy-detail-item">
                  <div className="policy-detail-label">Coverage</div>
                  <div className="policy-detail-value" style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
                    {getCoverageIcon(policy.coverageType)}
                    {policy.coverageType}
                  </div>
                </div>
                <div className="policy-detail-item">
                  <div className="policy-detail-label">Premium Paid</div>
                  <div className="policy-detail-value" style={{ color: 'var(--accent-blue)' }}>
                    {formatCurrency(policy.premiumPaid)}
                  </div>
                </div>
                <div className="policy-detail-item">
                  <div className="policy-detail-label">Max Payout</div>
                  <div className="policy-detail-value" style={{ color: 'var(--accent-emerald)' }}>
                    {formatCurrency(policy.maxPayout)}
                  </div>
                </div>
                <div className="policy-detail-item">
                  <div className="policy-detail-label">Period</div>
                  <div className="policy-detail-value" style={{ fontSize: '0.82rem' }}>
                    {policy.startDate} — {policy.endDate}
                  </div>
                </div>
              </div>

              <div className="policy-card-footer">
                <div style={{ display: 'flex', alignItems: 'center', gap: 6, fontSize: '0.78rem', color: 'var(--text-muted)' }}>
                  <Calendar size={13} />
                  Ends {policy.endDate}
                </div>
                <div style={{ display: 'flex', gap: '0.5rem' }}>
                  <button
                    className="btn btn-outline btn-sm"
                    onClick={() => handleDownloadInvoice(policy.id)}
                    disabled={downloading === policy.id}
                    title="Download Invoice"
                  >
                    {downloading === policy.id ? <Loader2 size={14} style={{ animation: 'spin 1s linear infinite' }} /> : <Download size={14} />}
                  </button>
                  {policy.status === 'ACTIVE' ? (
                    <button
                      className="btn btn-danger btn-sm"
                      onClick={() => handleCancel(policy.id)}
                      disabled={cancelling === policy.id}
                    >
                      {cancelling === policy.id ? <Loader2 size={14} style={{ animation: 'spin 1s linear infinite' }} /> : <XCircle size={14} />}
                      {cancelling === policy.id ? '' : ' Cancel'}
                    </button>
                  ) : (
                    <span style={{ color: 'var(--text-muted)', fontSize: '0.78rem' }}></span>
                  )}
                </div>
              </div>
            </div>
          ))}
        </div>
      ) : (
        <div className="glass-card empty-state">
          <div className="empty-state-icon"><ClipboardList size={28} /></div>
          <h3>No policies yet</h3>
          <p>Purchase an insurance plan to get started with protection</p>
        </div>
      )}
    </div>
  );
}

export default Policies;

import { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext.jsx';
import { workerApi, otpApi } from '../api/api.js';
import {
  Zap, User, Mail, Lock, Phone, MapPin, Briefcase,
  Eye, EyeOff, ArrowRight, Shield, Brain, Banknote,
  AlertCircle, CheckCircle2, KeyRound, Loader2
} from 'lucide-react';

function Register() {
  const [form, setForm] = useState({
    fullName: '', email: '', password: '',
    phone: '', city: '', platformName: '',
  });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const [showPassword, setShowPassword] = useState(false);

  // Password strength
  const getPasswordStrength = (password) => {
    let score = 0;
    const checks = {
      length: password.length >= 8,
      number: /[0-9]/.test(password),
      special: /[!@#$%^&*()_+\-=\[\]{};':"\\|,.<>\/?]/.test(password),
      upper: /[A-Z]/.test(password),
    };
    if (checks.length) score++;
    if (checks.number) score++;
    if (checks.special) score++;
    if (checks.upper) score++;
    const labels = ['', 'Weak', 'Fair', 'Good', 'Strong'];
    const colors = ['', '#ef4444', '#f59e0b', '#3b82f6', '#10b981'];
    return { score, label: labels[score], color: colors[score], checks };
  };
  const pwStrength = getPasswordStrength(form.password);

  // OTP States
  const [step, setStep] = useState('register'); // 'register' | 'otp'
  const [otpCode, setOtpCode] = useState('');
  const [otpLoading, setOtpLoading] = useState(false);
  const [registeredWorker, setRegisteredWorker] = useState(null);

  const { login } = useAuth();
  const navigate = useNavigate();

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
    setError('');
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!form.fullName || !form.email || !form.password || !form.phone || !form.city) {
      setError('Please fill in all required fields');
      return;
    }
    setLoading(true);
    setError('');
    try {
      // Step 1: Register the worker
      const response = await workerApi.register(form);
      setRegisteredWorker(response.data);

      // Step 2: Send OTP to the email
      await otpApi.sendOtp({ email: form.email });
      setStep('otp');
    } catch (err) {
      setError(err.message || 'Registration failed');
    } finally {
      setLoading(false);
    }
  };

  const handleVerifyOtp = async (e) => {
    e.preventDefault();
    if (!otpCode || otpCode.length !== 6) {
      setError('Please enter a valid 6-digit OTP');
      return;
    }
    setOtpLoading(true);
    setError('');
    try {
      // Verify OTP
      await workerApi.verifyEmail({ email: form.email, otpCode });
      // Login the user
      login({ ...registeredWorker, emailVerified: true });
      navigate('/dashboard');
    } catch (err) {
      setError(err.message || 'OTP verification failed');
    } finally {
      setOtpLoading(false);
    }
  };

  const handleResendOtp = async () => {
    setOtpLoading(true);
    setError('');
    try {
      await otpApi.sendOtp({ email: form.email });
      setError('');
    } catch (err) {
      setError(err.message);
    } finally {
      setOtpLoading(false);
    }
  };

  return (
    <div className="auth-layout">
      <div className="auth-hero">
        <div className="auth-hero-content">
          <div className="auth-hero-logo">
            <div className="auth-hero-logo-icon">
              <Zap size={28} />
            </div>
            <h1>GigShield AI</h1>
          </div>
          <p className="auth-hero-tagline">
            Join thousands of gig workers who protect their income with
            AI-powered parametric insurance.
          </p>
          <div className="auth-hero-features">
            <div className="auth-hero-feature">
              <div className="auth-hero-feature-icon blue">
                <Brain size={20} />
              </div>
              <div className="auth-hero-feature-text">
                <h4>AI Risk Prediction</h4>
                <p>Scikit-learn models predict income disruption risk</p>
              </div>
            </div>
            <div className="auth-hero-feature">
              <div className="auth-hero-feature-icon emerald">
                <Banknote size={20} />
              </div>
              <div className="auth-hero-feature-text">
                <h4>Instant Payouts</h4>
                <p>Approved claims paid out automatically via UPI</p>
              </div>
            </div>
            <div className="auth-hero-feature">
              <div className="auth-hero-feature-icon purple">
                <Shield size={20} />
              </div>
              <div className="auth-hero-feature-text">
                <h4>Full Coverage</h4>
                <p>Rain, heat, and pollution — all covered</p>
              </div>
            </div>
          </div>
        </div>
      </div>

      <div className="auth-form-side">
        <div className="auth-card">
          {step === 'register' ? (
            <>
              <div className="auth-card-header">
                <h2>Create your account</h2>
                <p>Get protected with AI-powered insurance</p>
              </div>

              {error && (
                <div className="alert alert-error">
                  <AlertCircle size={16} />
                  {error}
                </div>
              )}

              <form onSubmit={handleSubmit} className="stagger-children">
                <div className="form-group animate-fade-in-up">
                  <label className="form-label" htmlFor="reg-name">Full Name *</label>
                  <div className="form-input-wrapper" title="Enter your official full name">
                    <span className="form-input-icon"><User size={16} /></span>
                    <input
                      id="reg-name" className="form-input has-icon" type="text"
                      name="fullName" placeholder="e.g. Rajesh Kumar"
                      value={form.fullName} onChange={handleChange}
                    />
                  </div>
                </div>

                <div className="form-group animate-fade-in-up" style={{ animationDelay: '100ms' }}>
                  <label className="form-label" htmlFor="reg-email">Email Address *</label>
                  <div className="form-input-wrapper" title="We will send an OTP to verify your email">
                    <span className="form-input-icon"><Mail size={16} /></span>
                    <input
                      id="reg-email" className="form-input has-icon" type="email"
                      name="email" placeholder="you@example.com"
                      value={form.email} onChange={handleChange}
                    />
                  </div>
                </div>

                <div className="form-row animate-fade-in-up" style={{ animationDelay: '200ms' }}>
                  <div className="form-group">
                    <label className="form-label" htmlFor="reg-password">Password *</label>
                    <div className="form-input-wrapper" title="Create a strong password (min 8 chars, 1 number, 1 special)">
                      <span className="form-input-icon"><Lock size={16} /></span>
                      <input
                        id="reg-password" className="form-input has-icon"
                        type={showPassword ? 'text' : 'password'}
                        name="password" placeholder="Min 8 chars, special"
                        value={form.password} onChange={handleChange}
                      />
                      <button type="button" className="password-toggle"
                        onClick={() => setShowPassword(!showPassword)} tabIndex={-1}>
                        {showPassword ? <EyeOff size={16} /> : <Eye size={16} />}
                      </button>
                    </div>
                    {form.password && (
                      <div className="animate-fade-in" style={{ marginTop: '8px' }}>
                        <div style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '6px' }}>
                          <div style={{ flex: 1, height: '4px', borderRadius: '2px', background: 'rgba(255,255,255,0.1)' }}>
                            <div style={{ width: `${pwStrength.score * 25}%`, height: '100%', borderRadius: '2px', background: pwStrength.color, transition: 'all 0.3s ease' }} />
                          </div>
                          <span style={{ fontSize: '0.72rem', fontWeight: 600, color: pwStrength.color, minWidth: '40px' }}>{pwStrength.label}</span>
                        </div>
                        <div style={{ display: 'flex', gap: '12px', flexWrap: 'wrap' }}>
                          {[['length', '8+ chars'], ['number', '1 number'], ['special', '1 special'], ['upper', '1 uppercase']].map(([key, lbl]) => (
                            <span key={key} style={{ fontSize: '0.7rem', color: pwStrength.checks[key] ? 'var(--accent-emerald)' : 'var(--text-tertiary)', display: 'flex', alignItems: 'center', gap: '3px', transition: 'color 0.2s' }}>
                              {pwStrength.checks[key] ? '✓' : '○'} {lbl}
                            </span>
                          ))}
                        </div>
                      </div>
                    )}
                  </div>
                  <div className="form-group">
                    <label className="form-label" htmlFor="reg-phone">Phone *</label>
                    <div className="form-input-wrapper" title="Your active mobile number for payout alerts">
                      <span className="form-input-icon"><Phone size={16} /></span>
                      <input
                        id="reg-phone" className="form-input has-icon" type="tel"
                        name="phone" placeholder="+91 98765 43210"
                        value={form.phone} onChange={handleChange}
                      />
                    </div>
                  </div>
                </div>

                <div className="form-row animate-fade-in-up" style={{ animationDelay: '300ms' }}>
                  <div className="form-group">
                    <label className="form-label" htmlFor="reg-city">City *</label>
                    <div className="form-input-wrapper" title="Your primary working city for weather data">
                      <span className="form-input-icon"><MapPin size={16} /></span>
                      <input
                        id="reg-city" className="form-input has-icon" type="text"
                        name="city" placeholder="e.g. Mumbai"
                        value={form.city} onChange={handleChange}
                      />
                    </div>
                  </div>
                  <div className="form-group">
                    <label className="form-label" htmlFor="reg-platform">Platform</label>
                    <div className="form-input-wrapper" title="Which service do you deliver for?">
                      <span className="form-input-icon"><Briefcase size={16} /></span>
                      <input
                        id="reg-platform" className="form-input has-icon" type="text"
                        name="platformName" placeholder="e.g. Swiggy"
                        value={form.platformName} onChange={handleChange}
                      />
                    </div>
                  </div>
                </div>

                <button
                  type="submit" className={`btn btn-primary btn-full animate-fade-in-up ${loading ? 'btn-loading' : ''}`}
                  disabled={loading} style={{ marginTop: '12px', animationDelay: '400ms' }}
                >
                  {!loading && <>Create Account <ArrowRight size={16} /></>}
                </button>
              </form>

              <div className="auth-social-login animate-fade-in-up" style={{ marginTop: '24px', animationDelay: '500ms' }}>
                <div style={{ display: 'flex', alignItems: 'center', gap: '12px', marginBottom: '16px' }}>
                  <div style={{ flex: 1, height: '1px', background: 'var(--border-color)' }}></div>
                  <span style={{ fontSize: '0.8rem', color: 'var(--text-muted)' }}>Or continue with</span>
                  <div style={{ flex: 1, height: '1px', background: 'var(--border-color)' }}></div>
                </div>

                <div style={{ display: 'flex', gap: '12px' }}>
                  <button className="auth-provider-btn" style={{ flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '8px' }}>
                    <svg width="18" height="18" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
                      <path fill="#4285F4" d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z" />
                      <path fill="#34A853" d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z" />
                      <path fill="#FBBC05" d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z" />
                      <path fill="#EA4335" d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z" />
                    </svg>
                    Google
                  </button>
                  <button className="auth-provider-btn" style={{ flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '8px' }}>
                    <svg width="18" height="18" viewBox="0 0 24 24" fill="#1877F2" xmlns="http://www.w3.org/2000/svg">
                      <path d="M24 12.073c0-6.627-5.373-12-12-12s-12 5.373-12 12c0 5.99 4.388 10.954 10.125 11.854v-8.385H7.078v-3.47h3.047V9.43c0-3.007 1.792-4.669 4.533-4.669 1.312 0 2.686.235 2.686.235v2.953H15.83c-1.491 0-1.956.925-1.956 1.874v2.25h3.328l-.532 3.47h-2.796v8.385C19.612 23.027 24 18.062 24 12.073z" />
                    </svg>
                    Facebook
                  </button>
                </div>
              </div>

              <div className="auth-footer animate-fade-in-up" style={{ animationDelay: '600ms' }}>
                Already have an account?{' '}
                <Link to="/login">Sign in</Link>
              </div>
            </>
          ) : (
            <>
              <div className="auth-card-header">
                <h2>Verify your email</h2>
                <p>Enter the 6-digit OTP sent to <strong>{form.email}</strong></p>
              </div>

              {error && (
                <div className="alert alert-error">
                  <AlertCircle size={16} />
                  {error}
                </div>
              )}

              <div className="otp-section">
                <div style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 'var(--space-md)' }}>
                  <KeyRound size={18} style={{ color: 'var(--accent-emerald)' }} />
                  <span style={{ fontSize: '0.88rem', fontWeight: 600 }}>OTP Verification</span>
                </div>
                <p style={{ fontSize: '0.82rem', color: 'var(--text-secondary)', marginBottom: 'var(--space-md)' }}>
                  For demo purposes, the OTP is returned in the API response and logged to the backend console.
                </p>

                <form onSubmit={handleVerifyOtp}>
                  <div className="form-group">
                    <label className="form-label" htmlFor="otp-input">Enter OTP Code</label>
                    <div className="otp-input-group">
                      <input
                        id="otp-input"
                        className="form-input"
                        type="text"
                        maxLength={6}
                        placeholder="000000"
                        value={otpCode}
                        onChange={(e) => { setOtpCode(e.target.value.replace(/\D/g, '').slice(0, 6)); setError(''); }}
                        style={{ fontSize: '1.2rem', fontWeight: 700, letterSpacing: '8px', textAlign: 'center' }}
                      />
                    </div>
                  </div>

                  <button
                    type="submit" className="btn btn-primary btn-full"
                    disabled={otpLoading || otpCode.length !== 6}
                  >
                    {otpLoading ? (
                      <><Loader2 size={16} style={{ animation: 'spin 1s linear infinite' }} /> Verifying...</>
                    ) : (
                      <><CheckCircle2 size={16} /> Verify & Continue</>
                    )}
                  </button>
                </form>

                <div style={{ textAlign: 'center', marginTop: 'var(--space-md)' }}>
                  <button
                    className="btn btn-ghost btn-sm"
                    onClick={handleResendOtp}
                    disabled={otpLoading}
                    style={{ fontSize: '0.82rem' }}
                  >
                    Didn't receive? Resend OTP
                  </button>
                </div>
              </div>

              <div className="auth-footer" style={{ marginTop: 'var(--space-lg)' }}>
                <button
                  className="btn btn-ghost btn-sm"
                  onClick={() => { setStep('register'); setError(''); setOtpCode(''); }}
                >
                  ← Back to registration
                </button>
              </div>
            </>
          )}
        </div>
      </div>
    </div>
  );
}

export default Register;
